var e=JSON.parse(`[{"id":"L4_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"그래. 지금 그의 이름은 속삭이는 자, <color=#ffd34c>네헤모트</color>.","JPN":"そう。今の彼の名前は囁く者、<color=#ffd34c>ネヘモト</color>。","ENG":"Correct. His new name is <color=#ffd34c>Nehemoth</color> the Whisperer.","TWN":"沒錯，他現在的名字是私語者 <color=#ffd34c>貝赫莫特</color>。"},"stage":{"bg":"MAINSTREAM_7130013","bgm":"CUTSCENE_TALK_04","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L5_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"가짜 구세주, 실패한 구원자라고도 불리는……","JPN":"偽の救世主、失敗した救世主とも呼ばれる……","ENG":"Also known as the False Savior, the Fallen Shepherd…","TWN":"也有人稱他是假救世主，失敗的救贖者……"},"stage":{"bg":"MAINSTREAM_7130013","bgm":"CUTSCENE_TALK_04","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L6_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"클리포트의 마왕들 중 하나다.","JPN":"クリフォトの魔王の一人だ。","ENG":"He's one of the Demon Lords of Qliphoth.","TWN":"是逆卡巴拉的魔王之一。"},"stage":{"bg":"MAINSTREAM_7130013","bgm":"CUTSCENE_TALK_04","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L8_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"……라더니!","JPN":"……って言ってたけど！","ENG":"... That’s what I heard!","TWN":"……就說這樣！"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"그래서 클리포트의 마왕들이란 게 대체 뭔데? 실패한 구원자는 또 뭐고?","JPN":"クリフォトの魔王って何？　失敗した救世主って何？","ENG":"So who are these Demon Lords of Qliphoth? Who is the Fallen Shepherd?","TWN":"所以逆卡巴拉的魔王是什麼？失敗的救贖者又是什麼？"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"결국 아무것도 알려 준 게 없잖아!","JPN":"結局、肝心なことは何も教えてくれてないじゃん！","ENG":"So in the end, they told me nothing!","TWN":"根本都沒解釋啊！"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"그러더니 부사장님은 의뢰가 들어왔으니 일이나 하라고 이렇게 보내버리고.","JPN":"なのに副社長ったら、依頼が入ったから仕事しろって言ってくるし。","ENG":"Then the Vice President sent me away on a mission.","TWN":"後來副總又說什麼有工作進來，就叫我先去做事，然後我就在這裡啦！"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"으으, 생각했더니 또 열 받아!","JPN":"うぐぐ……思い出したらまたイライラしてきた！","ENG":"Urgh! It makes me angry all over again!","TWN":"可惡，想起來還是覺得上火！"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"하하. 진정하세요, 미나 양. 다른 손님들이 여길 노려보고 있거든요.","JPN":"ハハ。落ち着いてください、ミナさん。周りのお客さんに見られてますよ。","ENG":"Haha, calm down, Mina. Other customers are glaring at you.","TWN":"哈哈，米娜，你冷靜點，大家都在看我們欸。"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L16_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"……선배, 선배는 혹시 뭔가 들은 거 있어?","JPN":"……先輩、先輩はもしかして何か聞いてない？","ENG":"Shiyoon, do you know anything about this?","TWN":"……前輩，你有聽說什麼嗎？"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L17_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"글쎄요…… 지난 주에 시작한 모바일 게임에 마왕인가 뭔가가 나왔던 것 같긴 한데 말이죠.","JPN":"そうですね……先週始まったモバイルゲームの中に\\n魔王とか何かが出てきた気がしますが。","ENG":"Um... I did see a demon lord in the mobile game I started playing last week.","TWN":"這個嘛……我是有聽說，上個禮拜出的新手遊裡面是有魔王沒錯啦。"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L18_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"누가 게임 이야기 물어봤어? 자꾸 그런 식으로 말 돌리기만 할 거야?","JPN":"誰もゲームの話なんか聞いてないよ？　とぼけないでよ！","ENG":"I’m not talking about a game! Stop changing the subject.","TWN":"誰在跟你講遊戲的事啦！你又在給我轉移話題對不對！"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L19_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"정말 모르는 일이라서요, 어쩔 수 없죠.","JPN":"本当にわからないので、しょうがないですよ。","ENG":"I can’t help it. I really don’t know anything.","TWN":"沒辦法，我就真的不知道嘛～"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L20_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"오히려 긍정적으로 생각해 보세요. 스승님이 최소한 입을 열긴 했잖아요.","JPN":"こういう時はポジティブに考えてみてください。あの師匠が一応ヒントをくれたんですから。","ENG":"Well, look on the bright side. At least the Master brought up the topic.","TWN":"我們換個角度想，起碼師父還有對你開金口。"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L21_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"전 그것만 해도 거의 10년이나 걸렸다고요.","JPN":"僕なんてそれすら10年ぐらいかかったんですからね。","ENG":"It took me almost ten years for that.","TWN":"我可是花了快10年的時間，才等到她開金口欸。"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L22_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"선배도 소대장 상대하느라 고생이 참 많았겠다…….","JPN":"先輩も小隊長を相手に大変だね……","ENG":"It must have been very hard for you, dealing with the Commander all those years...","TWN":"前輩要和小隊長打交道應該也很辛苦吧……"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L23_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"괜찮습니다. 저야 워낙 어릴 때부터 스승님이랑 지내서 이제 익숙하니까요.","JPN":"大丈夫ですよ。\\n僕は幼いころから師匠と過ごしてきたので、もう慣れています。","ENG":"I’m okay. I’ve been with her since I was young; I'm used to it.","TWN":"沒事的，我從小就和師父一起生活，早就習慣了。"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L25_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"어릴 때라…….","JPN":"幼いころかぁ……","ENG":"Since you were young...","TWN":"從小……"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"선배 어릴 때는 어땠어? 관리부장님 말로는 엄청 귀여웠다던데?","JPN":"先輩はどんな子どもだったの？　管理部長はすっごく可愛かったって言ってたけど？","ENG":"What were you like when you were young? The Manager told me that you used to be super cute.","TWN":"前輩小時候長怎樣？聽管理部長說你小時候很可愛？"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"하하, 지금은 아니라는 것처럼 들려서 슬프네요.","JPN":"ハハ、まるで今は違うという風に聞こえて少し悲しくなりました。","ENG":"Haha, it sounds like I'm not now. That's sad.","TWN":"哈哈，真令人難過，意思是現在不可愛嗎？"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L30_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"양심이 있으면 그런 걸로 슬퍼하면 안 되지…….","JPN":"今までのことに自覚があるなら、そんなことで悲しんじゃだめでしょ……","ENG":"You shouldn’t be depressed by the truth...","TWN":"說這種話你的良心不會痛嗎……"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L32_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"아, 미나 양. 저기 의뢰인께서 오신 것 같네요.","JPN":"あっ、ミナさん。依頼主がいらしたようですよ。","ENG":"Oh, Mina. Our client is here.","TWN":"米娜，那位好像就是委託人。"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"CHARLOTTE_ORDER_NULL_NULL","text":{"KOREA":"……그대들이 코핀 컴퍼니에서 온 자들인가?","JPN":"……そなたたちがコフィンカンパニーから来た者なのか？","ENG":"Are you the ones from Coffin Company?","TWN":"……你們是科芬公司派來的嗎？"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHARLOTTE_ORDER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"그렇습니다. 그리고 그쪽이 저희에게 의뢰를 맡기신 분인가 보군요.","JPN":"そうです。あなたが依頼主の方ですね。","ENG":"Yes, we are. You must be our client.","TWN":"是的，請問你就是委託人嗎？"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L40_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"완전 어린애잖아? 이런 꼬마가 무슨 의뢰를 한다는 거야?","JPN":"えっ、子どもじゃない。こんなチビがなんの依頼をするっていうの？","ENG":"She’s a kid. Do we take jobs from kids now?","TWN":"根本就只是個小丫頭嘛！一個小丫頭是要委託什麼？"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L42_1","type":"dialog","speaker":"CHARLOTTE_ORDER_NULL_NULL","text":{"KOREA":"그렇군. 어린 모습으로 그대를 혼란하게 해서 미안하다.","JPN":"そうだな。幼い姿のせいで君に混乱を与えてすまない。","ENG":"I apologize if my look confused you.","TWN":"原來如此，抱歉，因為我稚氣的外表造成你們的誤會。"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHARLOTTE_ORDER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"CHARLOTTE_ORDER_NULL_NULL","text":{"KOREA":"하지만 이래 보여도 한 가문의 의무를 짊어지고 있는 몸.","JPN":"だが、こう見えても一族を背負っている身。","ENG":"Though I may look young, I bear the banner of my family.","TWN":"雖然我外表稚氣，但我身負家族的義務。"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHARLOTTE_ORDER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"CHARLOTTE_ORDER_NULL_NULL","text":{"KOREA":"이번 의뢰는 나에겐 아주 중요한 일이니 최선을 다해주기 바란다.","JPN":"今回の依頼は私にとって重要な案件だ。どうか最善を尽くしてほしい。","ENG":"And my request is very important, so I expect you to do your best.","TWN":"這次的委託對我非常重要，請務必要使命必達。"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHARLOTTE_ORDER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"미, 미안……. 초면에 내가 너무 무례하게 말했던 것 같아.","JPN":"ご、ごめん……初対面なのにあまりにも失礼だったよね。","ENG":"I-I’m sorry. I guess I was being rude.","TWN":"抱…抱歉……才第一次見面，我說話就這麼不客氣。"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L48_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"하하, 모습도 그렇고 말투도 그렇고 특이하신 분이네요.","JPN":"ハハ、姿も話し方もとても個性的な方ですね。","ENG":"Haha. Your looks and the way you talk—they’re all very unique.","TWN":"哈哈，你的穿著跟說話的方式都很特別呢。"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L49_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"그나저나 관리국에 확인해 보니 저희 둘을 직접 지명해서 의뢰를 맡기셨다고 하던데…….","JPN":"そういえば、管理局から聞いた話だと、\\nご依頼の際に僕たちをご指名されたと聞きましたが……","ENG":"Anyway, when I checked with the Administration, they told me you specifically chose us two.","TWN":"不過我聽管理局的說，你是指明要委託我們兩個人嗎……"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L50_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"특별한 이유가 있으신가요?","JPN":"特別な理由があるのですか？","ENG":"Is there a reason?","TWN":"是有什麼特殊原因嗎？"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L1_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"이런 말 하긴 그렇지만, 저희 회사보다는 좀 더 믿을 만한 곳도 많을 텐데요.","JPN":"こんなことを言ってしまうとあれですが、\\n弊社よりも信頼できる会社はたくさんあると思います。","ENG":"I know this is not my place to say, but there are other companies that are better than us.","TWN":"雖然這樣說有點滅自己威風，但應該有很多比我們公司更值得信賴的公司吧？"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L3_1","type":"dialog","speaker":"CHARLOTTE_ORDER_NULL_NULL","text":{"KOREA":"……추천을 받았다.","JPN":"……紹介を受けた。","ENG":"Someone recommended you.","TWN":"……是有人跟我推薦的。"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHARLOTTE_ORDER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"CHARLOTTE_ORDER_NULL_NULL","text":{"KOREA":"그리고 그대들이 내가 알던 이들과 닮았기 때문이기도 하고.","JPN":"そして、そなたたちが私の知る人物に似ていることも理由の一つだ。","ENG":"And you resemble someone I knew.","TWN":"而且你們和長得像我認識的人。"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHARLOTTE_ORDER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"흐음…… 추천이라.","JPN":"ふむ……紹介でしたか。","ENG":"Hmm, someone recommended us, huh?","TWN":"嗯……有人推薦喔。"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L8_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"누구랑 닮았다는 말은 별로 들어본 적이 없는데…… 친구였어?","JPN":"誰かに似ているなんてあまり言われたことないけど……お友達とかかな？","ENG":"There’s someone who looks like me? I don’t hear that often. Who was it, your friend?","TWN":"我第一次聽到有人說我長得像某人……是像你的朋友嗎？"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L10_1","type":"dialog","speaker":"CHARLOTTE_ORDER_NULL_NULL","text":{"KOREA":"친구…….","JPN":"友達……","ENG":"My friend...","TWN":"朋友……"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHARLOTTE_ORDER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"CHARLOTTE_ORDER_NULL_NULL","text":{"KOREA":"그래. 내게 친구를 만들 자격은 없지만……. 친구가 되어 준 이였다.","JPN":"そうだ。友達を作る資格なんてない私と……\\n友達になってくれた人だった。","ENG":"Yes. I was not qualified to have a friend... but she was willing to become one for me.","TWN":"是的，雖然我沒資格交朋友……但他願意做我的朋友。"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHARLOTTE_ORDER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"친구를 만드는 데도 자격이 필요해?","JPN":"友達を作るのに資格が必要なの？","ENG":"You don’t need a qualification to make a friend.","TWN":"交朋友還需要資格嗎？"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"CHARLOTTE_ORDER_NULL_NULL","text":{"KOREA":"……내 고향에서는 그렇다.","JPN":"……私の故郷ではそうだ。","ENG":"That’s how it was in my home.","TWN":"……在我的家鄉是這樣的。"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHARLOTTE_ORDER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"그래……. 특이한 풍습이네.","JPN":"ふーん……独特な習わしだね。","ENG":"Okay... That’s curious.","TWN":"是喔……真是奇怪的習俗。"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"뭐, 그래도 이쪽 동네에서는 친구 만드는 데 딱히 자격 같은 건 필요 없거든.","JPN":"まあでも、ここでは友達を作るのに資格なんか必要ないよ。","ENG":"Well, in this town, you don’t need qualifications to make friends.","TWN":"總之，在我們這裡交朋友是不需要什麼資格的！"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"……아니, 생각해 보니까 친구 자격증이 필요한 녀석도 있긴 하네.","JPN":"……いや、友達の資格が必要なヤツもいたわ。","ENG":"But then again, I can think of someone who might need to take such a test.","TWN":"……不對，確實有人是需要朋友資格證的。"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}},"sfx":"FX_COMBAT_ALL_MAGIC_SPELL_LIGHT_02"},{"id":"L21_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"어쨌든, 머리도 복잡했는데 잘됐네.","JPN":"とにかく、気分転換にちょうどよさそう！","ENG":"Well, I needed a change anyway.","TWN":"反正不管啦，正好我現在腦袋打結，"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHARLOTTE_ORDER_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L22_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"이렇게 만나게 된 것도 인연이니까, 진짜 친구 이상의 서비스 정신을 보여 줄게.","JPN":"これも何かの縁だし、\\n本当の友達以上のサービス精神ってやつを見せてあげるよ。","ENG":"I’ll help you like a friend. No, even better than a friend.","TWN":"既然能相遇就是緣份，我會用一顆服務朋友的心來服務你的！"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHARLOTTE_ORDER_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L23_1","type":"dialog","speaker":"CHARLOTTE_ORDER_NULL_NULL","text":{"KOREA":"그런가……?","JPN":"そうなのか……？","ENG":"Is that so?","TWN":"是嗎……？"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHARLOTTE_ORDER_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L24_1","type":"dialog","speaker":"CHARLOTTE_ORDER_NULL_NULL","text":{"KOREA":"감사를 표한다.","JPN":"礼を言う。","ENG":"I am much obliged.","TWN":"謝謝。"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHARLOTTE_ORDER_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L26_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"하하, 미나 양. 영업용 멘트가 점점 좋아지는 것 같네요.","JPN":"ハハ、ミナさん。営業トークに磨きがかかっていますね。","ENG":"Haha, Mina, your sales skills are getting better everyday.","TWN":"哈哈，米娜，你的話術越來越厲害囉～"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"이젠 제가 더 가르칠 것도 없는 것 같아요.","JPN":"もう僕が教えられることは無いようです。","ENG":"There’s nothing more for me to teach you.","TWN":"看來我已經沒什麼可以教你的囉～"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"여, 영업용 아니거든?!","JPN":"え、営業トークなんかじゃないよ！？","ENG":"Th-that was not a sales pitch!","TWN":"才…才不是話術咧！"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L31_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"아 참, 그런데 의뢰 내용이 뭐라고?","JPN":"あ！　ところで、依頼内容って何だっけ？","ENG":"Oh, what was that you wanted us to do?","TWN":"對了，都還沒說是什麼樣的委託呢？"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L33_1","type":"dialog","speaker":"CHARLOTTE_ORDER_NULL_NULL","text":{"KOREA":"……<color=#ffd34c>등대</color>를 찾으러 간다.","JPN":"……<color=#ffd34c>灯台</color>を探しに行く。","ENG":"... I’m looking for the <color=#ffd34c>Lighthouse</color>.","TWN":"……我要去找<color=#ffd34c>燈塔</color>。"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHARLOTTE_ORDER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};